def read_ints():
    return map(int, sys.stdin.readline().split())

def main():
    n, m = read_ints()
    graph = [[] for _ in range(n + 1)]
    total_disks = 0

    for _ in range(m):
        s1, s2, d = read_ints()
        graph[s1].append((s2, d))
        graph[s2].append((s1, d))
        total_disks += d

    def dfs(node, parent, graph, total_disks):
        count = 0
        for neighbor, disks in graph[node]:
            if neighbor != parent:
                count += dfs(neighbor, node, graph, total_disks)
        count += sum(disks for neighbor, disks in graph[node] if neighbor != parent)
        return count

    min_disks = float('inf')
    for i in range(1, n + 1):
        count = dfs(i, -1, graph, total_disks)
        if count * 2 == total_disks:
            min_disks = 0
            break
        if count * 2 > total_disks:
            min_disks = min(min_disks, count * 2 - total_disks)
        else:
            min_disks = min(min_disks, total_disks - count * 2)

    print(min_disks)

