def main():
    n, m = map(int, input().split())
    graph = defaultdict(list)
    total_disks = 0

    for _ in range(m):
        s1, s2, d = map(int, input().split())
        graph[s1].append((s2, d))
        graph[s2].append((s1, d))
        total_disks += d

    def bfs(start):
        visited = set([start])
        queue = deque([start])
        counts = {start: 0}

        while queue:
            node = queue.popleft()
            for neighbor, disks in graph[node]:
                if neighbor not in visited:
                    visited.add(neighbor)
                    queue.append(neighbor)
                    counts[neighbor] = disks - counts[node]

        total_count = sum(counts.values())
        if total_count % len(counts) != 0:
            return -1
        balance = total_count // len(counts)
        extra_disks = sum(abs(balance - count) for count in counts.values())
        return extra_disks // 2

    min_extra_disks = float('inf')
    for i in range(1, n + 1):
        if i not in graph:
            continue
        extra_disks = bfs(i)
        if extra_disks != -1:
            min_extra_disks = min(min_extra_disks, extra_disks)

    print(min_extra_disks)

