def encrypt(plaintext, key):
    plaintext = ''.join(filter(str.isalpha, plaintext)).lower()
    key = [ord(c) - ord('a') + 2 for c in key]
    n = len(plaintext)
    ciphertext = ['_'] * n
    i, direction = 0, 1
    for d in key:
        j = (d - 1) * direction
        while 0 <= i < n:
            if ciphertext[i] == '_':
                ciphertext[i] = plaintext[j]
                j += d
            i += direction
        i = (n - 1) * (direction == 1)  # Reset i to the other end
        direction *= -1  # Reverse direction for the next iteration
    # Fill in any remaining '_' with the rest of the plaintext
    i, direction = (n - 1) * (direction == 1), direction
    j = j * direction  # Continue from where we left off in plaintext
    while 0 <= i < n:
        if ciphertext[i] == '_':
            ciphertext[i] = plaintext[j]
            j += 1
        i += direction
    return ''.join(ciphertext)

def decrypt(ciphertext, key):
    key = [ord(c) - ord('a') + 2 for c in key]
    n = len(ciphertext)
    plaintext = []
    positions = list(range(n))
    direction = 1
    for d in key:
        new_positions = []
        for i in positions[::direction]:
            if (i + 1) % d == 0:
                plaintext.append(ciphertext[i])
            else:
                new_positions.append(i)
        positions = new_positions[::direction]
        direction *= -1
    # Append the remaining characters in the correct order
    if direction == 1:
        plaintext.extend([ciphertext[i] for i in positions])
    else:
        plaintext.extend([ciphertext[i] for i in positions[::-1]])
    return ''.join(plaintext)

def main():
    task, key = input().split()
    text = input().strip()
    if task == 'E':
        print(encrypt(text, key))
    else:
        print(decrypt(text, key))

if __name__ == "__main__":
