        while 0 <= j < n:
            if ciphertext[j] == '_':
                ciphertext[j] = plaintext[i]
                i += 1
            j += direction * d
        direction *= -1
    while i < n:
        j = (n - 1 if direction == 1 else 0)
        while 0 <= j < n:
            if ciphertext[j] == '_':
                ciphertext[j] = plaintext[i]
                i += 1
            j += direction
    return ''.join(ciphertext)

def decrypt(ciphertext, key):
    key = [ord(c) - ord('a') + 2 for c in key]
    n = len(ciphertext)
    plaintext = [''] * n
    indices = list(range(n))
    i, direction = 0, 1
    for d in key:
        j = (0 if direction == 1 else n - 1)
        count = 0
        while count < len(indices):
            if j in indices:
                plaintext[j] = ciphertext[i]
                indices.remove(j)
                i += 1
                count += 1
            j += direction * d
        direction *= -1
    for j in (sorted(indices) if direction == 1 else sorted(indices, reverse=True)):
