def leapfrog_encrypt(key, plaintext):
    key = [ord(c) - ord('a') + 2 for c in key]
    plaintext = ''.join(c for c in plaintext.lower() if c.isalpha())
    n = len(plaintext)
    ciphertext = ['_'] * n
    i, direction = 0, 1
    for d in key:
        j = (n - 1 if direction == -1 else 0)
        count = 0
        while count < n:
            if ciphertext[j] == '_':
                if i < n:
                    ciphertext[j] = plaintext[i]
                    i += 1
                count += 1
            if count < n:
                j += d * direction
                if j >= n:
                    j -= n
                elif j < 0:
                    j += n
    for j in range(n):
        if ciphertext[j] == '_':
            if i < n:
                ciphertext[j] = plaintext[i]
                i += 1
    return ''.join(ciphertext)

def leapfrog_decrypt(key, ciphertext):
    key = [ord(c) - ord('a') + 2 for c in key]
    n = len(ciphertext)
    positions = list(range(n))
    plaintext = [''] * n
    i, direction = 0, 1
    for d in key:
        j = (n - 1 if direction == -1 else 0)
        count = 0
        while count < n:
            if positions[j] != -1:
                if i < n:
                    plaintext[positions[j]] = ciphertext[i]
                    positions[j] = -1
                    i += 1
                count += 1
            if count < n:
                j += d * direction
                if j >= n:
                    j -= n
                elif j < 0:
                    j += n
    for j in range(n):
        if positions[j] != -1:
            if i < n:
                plaintext[positions[j]] = ciphertext[i]
                i += 1
    return ''.join(plaintext)

def main():
