        j = (0 if direction == 1 else len(ciphertext) - 1)
        while i < len(plaintext):
            if ciphertext[j] == '':
                ciphertext[j] = plaintext[i]
                i += 1
            j += direction
    return ''.join(ciphertext)

def decrypt(ciphertext, key):
    key = [ord(c) - ord('a') + 2 for c in key]
    plaintext = []
    indices = [i for i in range(len(ciphertext))]
    direction = 1
    for d in key:
        j = (0 if direction == 1 else len(indices) - 1)
        while indices:
            plaintext.append(ciphertext[indices[j]])
            indices.pop(j)
            j += direction * d
        direction *= -1
    if indices:
        j = (0 if direction == 1 else len(ciphertext) - 1)
        for _ in range(len(indices)):
            while ciphertext[j] not in plaintext:
                j += direction
            plaintext.append(ciphertext[j])
            j += direction
    return ''.join(plaintext)

