    for _ in range(t):
        initials = read_string()
        valid_initials = sum(1 for char in set(initials) if ord(char) - ord('A') < p)
        if valid_initials == len(set(initials)):
            initials_count[tuple(sorted(set(initials)))] += 1

    max_teams = 0
    unique_initials = list(initials_count.keys())
    num_unique_initials = len(unique_initials)

    def backtrack(index, count, used_problems):
        nonlocal max_teams
        if index == num_unique_initials:
            max_teams = max(max_teams, count)
            return
        backtrack(index + 1, count, used_problems)
        initials = unique_initials[index]
        if not any(char in used_problems for char in initials):
            backtrack(index + 1, count + initials_count[initials], used_problems | set(initials))

    backtrack(0, 0, set())
    print(max_teams)

