def get_subsequences(s: str, k: int) -> Set[str]:
    """Generate all possible subsequences of length k from the given string."""
    subsequences = set()
    def backtrack(index: int, path: str) -> None:
        if len(path) == k:
            subsequences.add(path)
            return
        for i in range(index, len(s)):
            backtrack(i + 1, path + s[i])
