def read_tree(n):
    tree = []
    for _ in range(n):
        level = input().split()
        tree.append(level)
    return tree

def evaluate_node(node, level, t, tree, memo):
    if (node, level) in memo:
        return memo[(node, level)]

    if level == len(tree) - 1:
        result = 1 if tree[level][node] == 'T' else 0, 0 if tree[level][node] == 'T' else 1
    else:
        node_type = 'A' if (level + 1) % 2 == (1 if t == 'A' else 0) else 'O'
        children = tree[level][node]
        children_true = 0
        children_false = 0
        for _ in range(int(children)):
            child_true, child_false = evaluate_node(node * int(children) + _, level + 1, t, tree, memo)
            children_true += child_true
            children_false += child_false

        if node_type == 'A':
            true_count = children_true
            false_count = min(children_false, default=1)
        else:
            true_count = min(children_true, default=1)
            false_count = children_false

        result = true_count, false_count

    memo[(node, level)] = result
    return result

