from collections import deque

def min_cost_flow(graph, source, sink):
    n = len(graph)
    level = [0] * n
    iter = [0] * n

    def bfs(s):
        nonlocal level
        level = [0] * n
        level[s] = 1
        queue = deque([s])
        while queue:
            v = queue.popleft()
            for w, cap, _ in graph[v]:
                if cap > 0 and level[w] == 0:
                    level[w] = level[v] + 1
                    queue.append(w)

    def dfs(v, t, f):
        if v == t:
            return f
        for i in range(iter[v], len(graph[v])):
            iter[v] = i
            w, cap, rev = e = graph[v][i]
            if cap > 0 and level[v] < level[w]:
                d = dfs(w, t, min(f, cap))
                if d > 0:
                    e[1] -= d
                    graph[w][rev][1] += d
                    return d
        return 0

    inf = float('inf')
    total_flow = 0
    while True:
        bfs(source)
        if level[sink] == 0:
            return total_flow
        iter = [0] * n
        while True:
            flow = dfs(source, sink, inf)
            if flow > 0:
                total_flow += flow
            else:
                break

def main():
