    for t in range(max(events[-1][0] + 1, M * (N + 1))):
        if belt[0] is None and next_plate < M:
            belt[0] = next_plate
            next_plate += 1
        takers = set()
        while event_index < E and events[event_index][0] == t:
            p = events[event_index][1]
            if belt[p + 1] is not None:
                bills[p] += costs[belt[p + 1]]
                takers.add(p + 1)
            event_index += 1
        for i in range(N, -1, -1):
            if i in takers:
                belt[i] = None
        belt = belt[-1:] + belt[:-1]
        if belt[0] is not None and next_plate < M:
            next_plate += 1
            belt[0] = next_plate - 1
        elif belt[0] is None and next_plate < M:
            belt[0] = next_plate
            next_plate += 1
        elif belt[0] is not None and next_plate >= M:
            belt[0] = belt[0] % M
