import sys
from collections import defaultdict

def main():
    input = sys.stdin.readline
    N, M = map(int, input().split())

    spies = {}
    x_coords = defaultdict(list)
    y_coords = defaultdict(list)

    for i in range(1, N + 1):
        x, y = map(int, input().split())
        spies[i] = (x, y)
        x_coords[x].append((y, i))
        y_coords[y].append((x, i))

    for coord_list in x_coords.values():
        coord_list.sort()
    for coord_list in y_coords.values():
        coord_list.sort()

    eliminated = set()

    for _ in range(M):
        team, direction = input().split()
        team = int(team)

        if team in eliminated:
            print('ignore')
            continue

        x, y = spies[team]
        eliminated_spies = []

        if direction == 'N':
            idx = binary_search(x_coords[x], y)
            for y_coord, spy in x_coords[x][idx:]:
                eliminated_spies.append(spy)
                eliminated.add(spy)
            x_coords[x] = x_coords[x][:idx]

        elif direction == 'S':
            idx = binary_search(x_coords[x], y, reverse=True)
            for y_coord, spy in x_coords[x][:idx+1]:
                eliminated_spies.append(spy)
                eliminated.add(spy)
            x_coords[x] = x_coords[x][idx+1:]

        elif direction == 'E':
            idx = binary_search(y_coords[y], x)
            for x_coord, spy in y_coords[y][idx:]:
                eliminated_spies.append(spy)
                eliminated.add(spy)
            y_coords[y] = y_coords[y][:idx]

        elif direction == 'W':
            idx = binary_search(y_coords[y], x, reverse=True)
            for x_coord, spy in y_coords[y][:idx+1]:
                eliminated_spies.append(spy)
                eliminated.add(spy)
            y_coords[y] = y_coords[y][idx+1:]

        if eliminated_spies:
            print(len(eliminated_spies), *eliminated_spies)
        else:
            print(0)

def binary_search(arr, target, reverse=False):
    left, right = 0, len(arr) - 1
    while left <= right:
        mid = (left + right) // 2
        if (not reverse and arr[mid][0] > target) or (reverse and arr[mid][0] < target):
            right = mid - 1
        else:
            left = mid + 1
    return left if not reverse else right

if __name__ == '__main__':
    main()
