                    remaining_spies.append((x_coord, spy))
            y_coords[y] = remaining_spies[::-1] + y_coords[y][idx:]

        if eliminated_spies:
            print(len(eliminated_spies), *eliminated_spies)
        else:
            print(0)

if __name__ == "__main__":
    main()
